{
  "summary": "This paper presents CORA, a unified multilingual open question answering model that jointly performs cross-lingual dense passage retrieval and answer generation without relying on external machine translation or language-specific modules. Using an iterative training approach leveraging Wikipedia language links and model predictions, CORA achieves state-of-the-art results on two multilingual QA benchmarks across 26 languages, including unseen languages, demonstrating improved cross-lingual retrieval and generation capabilities.",
  "strengths": [
    {
      "point": "Unified model for cross-lingual retrieval and generation",
      "evidence": "CORA jointly trains a multilingual dense passage retriever and an autoregressive answer generator, enabling cross-lingual retrieval and answer generation without external MT or language-specific components."
    },
    {
      "point": "Iterative training with data expansion",
      "evidence": "The model uses an iterative training approach that expands multilingual QA data using Wikipedia language links and model-generated pseudo-labels, improving performance especially on low-resource and unseen languages."
    },
    {
      "point": "Strong empirical results across many languages",
      "evidence": "CORA outperforms prior state-of-the-art by large margins on XOR-TYDI QA (+21.4 F1) and MKQA (+4.9 F1) benchmarks, including 9 unseen languages, demonstrating broad multilingual effectiveness."
    },
    {
      "point": "Comprehensive analysis and human evaluation",
      "evidence": "The paper provides ablations showing the importance of cross-lingual training and iterative data mining, as well as human evaluation confirming high relevance (96%) of retrieved passages."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to prior multilingual dense retrieval baselines",
      "evidence": "The paper lacks explicit baselines performing cross-lingual dense retrieval without MT, making it unclear how much CORA improves over existing multilingual dense retrievers."
    },
    {
      "point": "Limited methodological details on iterative training and data imbalance",
      "evidence": "No ablations or rationale are provided for iterative training design choices such as iteration count or stopping criteria; also, handling of language imbalance during training is not discussed."
    },
    {
      "point": "Evaluation gaps regarding MT baselines and metrics",
      "evidence": "No comparison to strong multilingual MT-based QA baselines is presented; evaluation focuses mainly on F1 score without metrics like Exact Match or human assessment of answer correctness and fluency."
    },
    {
      "point": "Reproducibility concerns due to missing details",
      "evidence": "Key details on retrieval index construction, training hyperparameters, and hardware are missing, hindering reproducibility."
    },
    {
      "point": "Clarity issues in illustrating cross-lingual retrieval and Wikipedia link usage",
      "evidence": "The paper does not clearly show examples of cross-lingual retrieval results or explain how Wikipedia language links are used and how noise in these links affects training."
    },
    {
      "point": "Limited discussion of practical limitations",
      "evidence": "No analysis of retrieval latency, computational costs, or handling of code-switching/mixed-language queries is provided."
    },
    {
      "point": "Generalisability limited to Wikipedia-based datasets",
      "evidence": "Evaluation is restricted to Wikipedia-based QA datasets, with no assessment on other domains or extremely low-resource/morphologically rich languages."
    }
  ],
  "questions": [
    {
      "question": "How does CORA compare to strong multilingual MT-based QA pipelines in terms of accuracy and efficiency?",
      "motivation": "Understanding this comparison is crucial to quantify the practical benefits of avoiding MT and to position CORA relative to existing competitive baselines."
    },
    {
      "question": "What are the effects of iterative training hyperparameters and noisy pseudo-labels on model convergence and stability?",
      "motivation": "Clarifying these aspects would help assess the robustness of the training approach and guide future improvements or replication."
    },
    {
      "question": "How does CORA handle language imbalance during training, and what is its performance on extremely low-resource or morphologically complex languages?",
      "motivation": "Addressing this would clarify the model's fairness and effectiveness across diverse languages, especially those underrepresented in training data."
    },
    {
      "question": "Can CORA effectively process code-switched or mixed-language questions, common in real-world multilingual scenarios?",
      "motivation": "This impacts the model's applicability in practical settings where users often mix languages."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
